<?php
namespace App\Http\Controllers;use App\Models\GoogleCalendarConnection;use App\Services\{GoogleCalendarService,UpcomingServiceCalendarService};use Carbon\Carbon;use Illuminate\Http\{JsonResponse,Request};
class CalendarController extends Controller{public function events(Request $r,UpcomingServiceCalendarService $services,GoogleCalendarService $google):JsonResponse{$d=$r->validate(['start'=>['required','date'],'end'=>['required','date','after:start'],'include_services'=>['sometimes','boolean'],'include_google'=>['sometimes','boolean'],'google_calendar_ids'=>['sometimes','array'],'google_calendar_ids.*'=>['string','max:1024']]);$start=Carbon::parse($d['start']);$end=Carbon::parse($d['end']);abort_if($start->diffInDays($end)>370,422,'The calendar date range may not exceed 370 days.');$result=['events'=>[],'warnings'=>[]];if($r->boolean('include_services',true))$result['events']=array_merge($result['events'],$services->events($start,$end));if($r->boolean('include_google')&&$r->user()->hasPermission('calendar.google.view')){$x=GoogleCalendarConnection::where('is_active',true)->latest()->first();if(!$x)$result['warnings'][]='Google Calendar is not connected.';else try{$ids=$d['google_calendar_ids']??$x->selected_calendar_ids??[];$result['events']=array_merge($result['events'],$google->events($x,$ids,$start->toIso8601String(),$end->toIso8601String()));}catch(\Throwable $e){$x->update(['last_error'=>$e->getMessage()]);$result['warnings'][]='Google Calendar is unavailable. Upcoming Services are still shown.';}}return response()->json($result);}}
